fn solve(m: i64, n: i64, wait_cost: Vec<Vec<i64>>) -> i64 {
    let rows = m as usize;
    let cols = n as usize;

    if rows == 0 || cols == 0 {
        return 0;
    }

    let mut dp = vec![vec![i64::MAX; cols]; rows];
    dp[0][0] = 1;

    for i in 0..rows {
        for j in 0..cols {
            if i == 0 && j == 0 {
                continue;
            }

            let enter = (i as i64 + 1) * (j as i64 + 1);
            let cost = if i == rows - 1 && j == cols - 1 {
                enter
            } else {
                enter + wait_cost[i][j]
            };

            let mut min_prev = i64::MAX;
            if i > 0 {
                min_prev = min_prev.min(dp[i-1][j]);
            }
            if j > 0 {
                min_prev = min_prev.min(dp[i][j-1]);
            }

            if min_prev != i64::MAX {
                dp[i][j] = min_prev + cost;
            }
        }
    }

    dp[rows-1][cols-1]
}
