    let m_usize = m as usize;
    let n_usize = n as usize;
    let mut dp_odd = vec![vec![i64::MAX; n_usize]; m_usize];
    let mut dp_even = vec![vec![i64::MAX; n_usize]; m_usize];

    if n_usize > 1 {
        dp_odd[0][1] = (0 + 1) * (0 + 1) + (0 + 1) * (1 + 1);
    }
    if m_usize > 1 {
        dp_odd[1][0] = (0 + 1) * (0 + 1) + (1 + 1) * (0 + 1);
    }

    for i in 0..m_usize {
        for j in 0..n_usize {
            if i > 0 {
                if dp_even[i - 1][j] != i64::MAX {
                    let cost_here = (i as i64 + 1) * (j as i64 + 1);
                    let total = dp_even[i - 1][j] + cost_here;
                    if total < dp_odd[i][j] {
                        dp_odd[i][j] = total;
                    }
                }
            }
            if j > 0 {
                if dp_even[i][j - 1] != i64::MAX {
