use std::collections::BinaryHeap;
use std::cmp::Reverse;

fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m_usize = m as usize;
    let n_usize = n as usize;
    if m_usize == 0 || n_usize == 0 {
        return 0;
    }
    let mut dist = vec![vec![[std::i64::MAX; 2]; n_usize]; m_usize];
    let mut heap = BinaryHeap::new();

    dist[0][0][1] = 1;
    heap.push(Reverse((1, 0, 0, 1)));

    while let Some(Reverse((cost, i, j, state))) = heap.pop() {
        if cost != dist[i][j][state] {
            continue;
        }
        if i == m_usize - 1 && j == n_usize - 1 && state == 0 {
            return cost;
        }

        if state == 1 {
            if i + 1 < m_usize {
                let ni = i + 1;
                let nj = j;
                let next_cost = cost + (ni as i64 + 1) * (j as i64 + 1);
                if next_cost < dist[ni][nj][0] {
                    dist[ni][nj][0] = next_cost;
                    heap.push(Reverse((next_cost, ni, nj, 0)));
                }
            }
            if j + 1 < n_usize {
                let ni = i;
                let nj = j + 1;
                let next_cost = cost + (i as i64 + 1) * (nj as i64 + 1);
                if next_cost < dist[ni][nj][0] {
                    dist[ni][nj][0] = next_cost;
                    heap.push(Reverse((next_cost, ni, nj, 0)));
                }
            }
        } else {
            let wait_cost_val = waitCost[i][j];
            let next_cost = cost + wait_cost_val;
            if next_cost < dist[i][j][1] {
                dist[i][j][1] = next_cost;
                heap.push(Reverse((next_cost, i, j, 1)));
            }
        }
    }

    dist[m_usize - 1][n_usize - 1][0]
}
